import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { toast } from 'react-toastify';

const ROLES = ['admin', 'hod', 'faculty', 'student'];
const SEMESTERS = [1,2,3,4,5,6,7,8];

const emptyForm = { name: '', rollNumber: '', role: 'student', department: '', semester: '', section: '' };

const roleBadge = { admin: 'badge-red', hod: 'badge-yellow', faculty: 'badge-purple', student: 'badge-blue' };

export default function AdminUsers() {
  const [users, setUsers] = useState([]);
  const [departments, setDepartments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [modal, setModal] = useState(false);
  const [editing, setEditing] = useState(null);
  const [form, setForm] = useState(emptyForm);
  const [saving, setSaving] = useState(false);
  const [filter, setFilter] = useState({ role: '', department: '' });
  const [search, setSearch] = useState('');

  const load = () => {
    const params = {};
    if (filter.role) params.role = filter.role;
    if (filter.department) params.department = filter.department;
    Promise.all([
      axios.get('/api/admin/users', { params }),
      axios.get('/api/admin/departments')
    ]).then(([uRes, dRes]) => {
      setUsers(uRes.data.users);
      setDepartments(dRes.data.departments.filter(d => d.isActive));
      setLoading(false);
    });
  };
  useEffect(load, [filter]);

  const openCreate = () => { setEditing(null); setForm(emptyForm); setModal(true); };
  const openEdit = (user) => {
    setEditing(user);
    setForm({ name: user.name, rollNumber: user.rollNumber, role: user.role, department: user.department?._id || '', semester: user.semester || '', section: user.section || '' });
    setModal(true);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.name.trim() || !form.rollNumber.trim()) return toast.error('Name and roll number are required');
    if (['hod','faculty','student'].includes(form.role) && !form.department) return toast.error(`Department is required for ${form.role}`);
    if (form.role === 'student' && !form.semester) return toast.error('Semester is required for students');
    setSaving(true);
    try {
      if (editing) {
        await axios.put(`/api/admin/users/${editing._id}`, form);
        toast.success('User updated');
      } else {
        await axios.post('/api/admin/users', form);
        toast.success(`User created! Default password: ${form.rollNumber.toUpperCase()}`);
      }
      setModal(false);
      load();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Error saving user');
    } finally {
      setSaving(false);
    }
  };

  const handleDeactivate = async (user) => {
    if (!window.confirm(`Deactivate user "${user.name}"?`)) return;
    try {
      await axios.delete(`/api/admin/users/${user._id}`);
      toast.success('User deactivated');
      load();
    } catch { toast.error('Failed'); }
  };

  const handleResetPassword = async (user) => {
    if (!window.confirm(`Reset password for "${user.name}" to their roll number?`)) return;
    try {
      await axios.put(`/api/admin/users/${user._id}/reset-password`);
      toast.success('Password reset to roll number');
    } catch { toast.error('Failed to reset password'); }
  };

  const filtered = users.filter(u => {
    if (!search) return true;
    const q = search.toLowerCase();
    return u.name.toLowerCase().includes(q) || u.rollNumber.toLowerCase().includes(q);
  });

  if (loading) return <div className="loading-screen"><div className="spinner"></div></div>;

  return (
    <div>
      <div className="page-header">
        <div>
          <div className="page-title">User Management</div>
          <div className="page-subtitle">Create and manage all role-based users</div>
        </div>
        <button className="btn btn-primary" onClick={openCreate}>＋ Add User</button>
      </div>

      {/* Filters */}
      <div className="filter-bar">
        <input className="form-input-sm" style={{ width: 220 }} placeholder="🔍 Search by name or roll no..." value={search} onChange={e => setSearch(e.target.value)} />
        <select className="form-select" style={{ width: 160 }} value={filter.role} onChange={e => setFilter({ ...filter, role: e.target.value })}>
          <option value="">All Roles</option>
          {ROLES.map(r => <option key={r} value={r}>{r.charAt(0).toUpperCase() + r.slice(1)}</option>)}
        </select>
        <select className="form-select" style={{ width: 200 }} value={filter.department} onChange={e => setFilter({ ...filter, department: e.target.value })}>
          <option value="">All Departments</option>
          {departments.map(d => <option key={d._id} value={d._id}>{d.name}</option>)}
        </select>
        <span className="text-muted" style={{ fontSize: 13 }}>{filtered.length} users</span>
      </div>

      <div className="card">
        <div className="table-wrapper">
          {filtered.length === 0 ? (
            <div className="empty-state"><div className="empty-icon">👥</div><div className="empty-text">No users found</div></div>
          ) : (
            <table>
              <thead>
                <tr><th>#</th><th>Name</th><th>Roll Number</th><th>Role</th><th>Department</th><th>Sem</th><th>Status</th><th>Actions</th></tr>
              </thead>
              <tbody>
                {filtered.map((user, i) => (
                  <tr key={user._id}>
                    <td>{i + 1}</td>
                    <td className="fw-600">{user.name}</td>
                    <td style={{ fontFamily: 'monospace', fontSize: 13 }}>{user.rollNumber}</td>
                    <td><span className={`badge ${roleBadge[user.role]}`}>{user.role}</span></td>
                    <td>{user.department?.name || <span className="text-muted">—</span>}</td>
                    <td>{user.semester || <span className="text-muted">—</span>}</td>
                    <td><span className={`badge ${user.isActive ? 'badge-green' : 'badge-red'}`}>{user.isActive ? 'Active' : 'Inactive'}</span></td>
                    <td>
                      <div className="gap-8">
                        <button className="btn btn-outline btn-sm" onClick={() => openEdit(user)}>✏️</button>
                        <button className="btn btn-outline btn-sm" title="Reset Password" onClick={() => handleResetPassword(user)}>🔑</button>
                        {user.isActive && <button className="btn btn-danger btn-sm" onClick={() => handleDeactivate(user)}>🗑</button>}
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>

      {modal && (
        <div className="modal-overlay" onClick={e => e.target === e.currentTarget && setModal(false)}>
          <div className="modal">
            <div className="modal-header">
              <span className="modal-title">{editing ? '✏️ Edit User' : '👤 Create User'}</span>
              <button className="modal-close" onClick={() => setModal(false)}>×</button>
            </div>
            <form onSubmit={handleSubmit}>
              <div className="modal-body">
                {!editing && (
                  <div className="info-box">Default password will be the roll number (uppercase).</div>
                )}
                <div className="form-row">
                  <div className="form-group">
                    <label className="form-label">Full Name *</label>
                    <input className="form-input" value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} placeholder="Full name" required />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Roll / Employee Number *</label>
                    <input className="form-input" value={form.rollNumber} onChange={e => setForm({ ...form, rollNumber: e.target.value })} placeholder="e.g. 22A51A0501" required disabled={!!editing} />
                  </div>
                </div>
                <div className="form-group">
                  <label className="form-label">Role *</label>
                  <select className="form-select" value={form.role} onChange={e => setForm({ ...form, role: e.target.value, department: '', semester: '' })}>
                    {ROLES.map(r => <option key={r} value={r}>{r.charAt(0).toUpperCase() + r.slice(1)}</option>)}
                  </select>
                </div>

                {['hod', 'faculty', 'student'].includes(form.role) && (
                  <div className="form-group">
                    <label className="form-label">Department *</label>
                    <select className="form-select" value={form.department} onChange={e => setForm({ ...form, department: e.target.value })} required>
                      <option value="">Select Department</option>
                      {departments.map(d => <option key={d._id} value={d._id}>{d.name} ({d.code})</option>)}
                    </select>
                  </div>
                )}

                {form.role === 'student' && (
                  <div className="form-row">
                    <div className="form-group">
                      <label className="form-label">Semester *</label>
                      <select className="form-select" value={form.semester} onChange={e => setForm({ ...form, semester: e.target.value })} required>
                        <option value="">Select Semester</option>
                        {SEMESTERS.map(s => <option key={s} value={s}>Semester {s}</option>)}
                      </select>
                    </div>
                    <div className="form-group">
                      <label className="form-label">Section</label>
                      <input className="form-input" value={form.section} onChange={e => setForm({ ...form, section: e.target.value.toUpperCase() })} placeholder="e.g. A" maxLength={3} />
                    </div>
                  </div>
                )}
              </div>
              <div className="modal-footer">
                <button type="button" className="btn btn-outline" onClick={() => setModal(false)}>Cancel</button>
                <button type="submit" className="btn btn-primary" disabled={saving}>{saving ? 'Saving...' : editing ? 'Update' : 'Create'}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
